head.script:
	scwin.initScreen = function() {
		//requires("uiplugin_.popup");
		scwin.parentObj = opener || parent;
		scwin.popupID = WebSquare.net.getParameter("popupID");
		var popupStr = WebSquare.util.getPopupParam();
		var paramJson = utilLib.parse(popupStr);
		scwin.closeCallbackFncName = paramJson.closeCallbackFncName;

		$p.$("#gridFile").css("hegiht","90");

		scwin.tobe_onComplete();

		defaultRows();

	};

	// 기본으로 화면에 5개의 Row를 만들어준다. 
	// 멀티업로드인 경우, 단일 파일 업로드인 경우는 하나만..
	function defaultRows() {
	    var fileInfos = new Array();
		for (var i=0; i < 5; i++) {
			fileInfos.push("");
			dataList1.setJSON(fileInfos);
		}
	}



	function selectCallback() {

		var fileInfos = new Array();
		var arrowFileInfo = new Array();
	 	fileInfos = tobe.getFileInfos();
		//첨부파일 업로드 가능여부체크
		var chkFile = "";
		if ( fileInfos.length < 5 ) {
			var i = 0;
			for ( i=0; i < fileInfos.length; i++) {
				chkFile = fileLib.multiUploadFileCheck(fileInfos[i]);
				if (chkFile) {
					arrowFileInfo.push(fileInfos[i]);
					dataList1.setJSON( arrowFileInfo );
				}
			}
			while (i < 5) {
				arrowFileInfo.push("");
				dataList1.setJSON(arrowFileInfo);
				i++;

			}		
		} else {
			for (var i=0; i < fileInfos.length; i++) {
				chkFile = fileLib.multiUploadFileCheck(fileInfos[i]);
				if (chkFile) {
					arrowFileInfo.push(fileInfos[i]);
					dataList1.setJSON( arrowFileInfo );
				}
			}
		}	
	}

	scwin.tobe_onprogress = function(info) {
//		console.log(info.fileName + "("+info.percentData+"%)");

		var rowidx = dataList1.getMatchedIndex("name", info.fileName);

		$("td[colindex='3']:eq("+rowidx+") .w2grid_input").text(info.percentData+"%");
		$("td[colindex='3']:eq("+rowidx+") .w2grid_input").css("width", info.percentData+"%");
	};

/*	
	function multiupload10_ondone(data) {
//		alert ( "첨부파일이 임시저장 저장되었습니다.");
		console.log(JSON.stringify(data));
		setTimeout( clearUpload, "3000" );
	};
*/	
	scwin.tobe_ondone = function(data) {

		console.log(JSON.stringify(data));
		scwin.parentObj.comLib.closePopup($p, scwin.popupID, scwin.closeCallbackFncName, data );
//		setTimeout( clearUpload, "1000" );
	};


	function clearUpload() {
		dataList1.removeAll();
	}

	scwin.textbox4_onclick = function(e) {
		var idxArr = gridFile.getCheckedJSON("chk");
		var idxArr1 = gridFile.getCheckedIndex( "chk" );
		for( var i=0;i<idxArr.length;i++ ) {
			var fileName = idxArr[i].name;
			tobe.removeFile( fileName );
		}
		dataList1.removeRows( idxArr1 );
	};

	scwin.textbox5_onclick = function(e) {
		tobe.startUpload();
	};

	//멀티 파일 업로드 컨포넌트 생성 후 기본값 셋팅	(Flash 모드에서만 작동하고 있음)
	scwin.tobe_onComplete = function() {
		tobe.setMaxFileCount(3); 
		tobe.setMaxFileSize( 1 * 1024 );     //현재 WebSquare 버전에서는 작동하지 않음. 패치가 필요함.(2017.06.12)
//		tobe.setMessageDuplicateText( "이미 등록된 동일파일이 존재합니다." );
	};

	scwin.textbox_insert_onclick = function(e) {

	};
